void Process::destroy()
{
    kout[Debug] << "Process destroy:" << id << endl;
    if (status == S_None) {
        return;
    } else if (status != S_Initing || status != S_Terminated) {
        exit(Exit_Normal);
    }
    while (fstChild) {
        fstChild->destroy();
    }
    if (broPre) {
        broPre->broNext = broNext;
    } else {
        if (father) {
            father->fstChild = broNext;
        }
    }
    if (broNext) {
        broNext->broPre = broPre;
    }
    setFa(nullptr);

    // if (VMS!=nullptr) {

    // }
    if (waitSem != nullptr) {
        delete waitSem;
        waitSem = nullptr;
    }
    if (curWorkDir != nullptr) {
        kfree(curWorkDir);
        curWorkDir = nullptr;
    }
    setName(nullptr);
    if (fo_head != nullptr) {
        destroyFds();
        kfree(fo_head);
        fo_head = nullptr;
    }
    if (Heap != nullptr) {
        kfree(Heap);
        Heap = nullptr;
    }
    if (stack != nullptr) {
        kfree(stack);
        stack = nullptr;
    }
    stacksize = 0;
    pm->freeProc(this);
    return;
}

bool Process::exit(int re)
{
    // kout<<"exit"<<re;
    switchStatus(S_Terminated);
    if (status != S_Terminated) {
        kout[Fault] << "Process ::Exit:status is not S_Terminated" << id << endl;
    }
    if (re != Exit_Normal) {
        kout[Warning] << "Process ::Exit:" << id << "exit with return value" << re << endl;
    }
    exitCode = re;
    // VMS->Leave();
    destroyFds();
    if (!(flags & F_AutoDestroy) && father != nullptr) {
        father->waitSem->signal();
    }
    return true;
}

