void VFSM::close(FAT32FILE* t)
{
    t->ref--;
    if (t->ref == 0) {
        if (t->pre) {
            t->pre->next = t->next;
        }
        if (t->next)
            t->next->pre = t->pre;
        delete t;
    }
}

