}
void VirtioDisk::free_chain(int i)
{
    while (1) {
        free_desc(i);
        if (desc[i].flags & VRING_DESC_F_NEXT)
            i = desc[i].next;
        else
            break;
    }
}
int VirtioDisk::alloc3_desc(int* idx)
{
    for (int i = 0; i < 3; i++) {
        idx[i] = alloc_desc();
        if (idx[i] < 0) {
            for (int j = 0; j < i; j++)
                free_desc(idx[j]);
            return -1;
        }
    }
    return 0;
}

